import { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import "./EmployeeForm.css";

function AddEmployee() {
  const navigate = useNavigate();
  const { id } = useParams();
  const isEditMode = Boolean(id);

  const [activeTab, setActiveTab] = useState("personal");

  const [employee, setEmployee] = useState({
    firstName: "",
    lastName: "",
    empId: "",
    gender: "",
    dob: "",
    maritalStatus: "",
    email: "",
    password: "",

    designation: "",
    department: "",
    salary: "",
    role: "",

    skills: [],
    tempSkill: "",
    customSkill: "",

    bankName: "",
    accountNumber: "",
    ifsc: "",

    qualification: "",
    university: "",
    passingYear: ""
  });

  const skillOptions = [
    "C","C++","Java","Advanced Java","Python",
    "NodeJS","React","Angular","MongoDB"
  ];

  // ===================== NEW: LOAD DESIGNATIONS =====================
  const [designations, setDesignations] = useState([]);

  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem("designations")) || [];
    setDesignations(saved);
  }, []);

  // ---------------- LOAD EMPLOYEE IN EDIT MODE ----------------
  useEffect(() => {
    if (!isEditMode) return;

    const employees = JSON.parse(localStorage.getItem("employees")) || [];
    const found = employees.find(e => String(e.id) === String(id));

    if (found) {
      const existingSkills = Array.isArray(found.skills)
        ? found.skills
        : found.skills
        ? [found.skills]
        : [];

      setEmployee(prev => ({
        ...prev,
        ...found,
        skills: existingSkills
      }));
    }
    // eslint-disable-next-line
  }, [id]);

  // ---------------- HANDLE INPUT CHANGE ----------------
  const handleChange = (e) => {
    setEmployee({
      ...employee,
      [e.target.name]: e.target.value
    });
  };

  // ---------------- ADD SKILL ----------------
  const addSkill = () => {
    let newSkill = "";

    if (employee.tempSkill === "Other") {
      if (!employee.customSkill.trim()) return;
      newSkill = employee.customSkill.trim();
    } else {
      if (!employee.tempSkill) return;
      newSkill = employee.tempSkill;
    }

    if (!employee.skills.includes(newSkill)) {
      setEmployee(prev => ({
        ...prev,
        skills: [...prev.skills, newSkill],
        tempSkill: "",
        customSkill: ""
      }));
    }
  };

  // ---------------- REMOVE SKILL ----------------
  const removeSkill = (skill) => {
    setEmployee(prev => ({
      ...prev,
      skills: prev.skills.filter(s => s !== skill)
    }));
  };

  // ---------------- SAVE EMPLOYEE ----------------
  const handleAdd = (e) => {
    e.preventDefault();

    let employees = JSON.parse(localStorage.getItem("employees")) || [];

    const newEmployee = {
      id: Date.now(),
      name: `${employee.firstName} ${employee.lastName}`.trim(),
      ...employee
    };

    employees.push(newEmployee);
    localStorage.setItem("employees", JSON.stringify(employees));

    alert("Employee Added Successfully!");
    navigate("/dashboard/employee-details");
  };

  // ---------------- UPDATE EMPLOYEE ----------------
  const handleUpdate = (e) => {
    e.preventDefault();

    let employees = JSON.parse(localStorage.getItem("employees")) || [];

    const updated = employees.map(emp =>
      String(emp.id) === String(id)
        ? {
            ...emp,
            ...employee,
            name: `${employee.firstName} ${employee.lastName}`.trim()
          }
        : emp
    );

    localStorage.setItem("employees", JSON.stringify(updated));

    alert("Employee Updated Successfully!");
    navigate("/dashboard/employee-details");
  };

  return (
    <div className="add-employee-page">
      <h2>{isEditMode ? "Edit Employee" : "Add Employee"}</h2>

      {/* ---------------- TABS ---------------- */}
      <div className="tabs">
        <button className={`tab ${activeTab === "personal" ? "active" : ""}`} onClick={() => setActiveTab("personal")}>PERSONAL</button>
        <button className={`tab ${activeTab === "employment" ? "active" : ""}`} onClick={() => setActiveTab("employment")}>EMPLOYMENT</button>
        <button className={`tab ${activeTab === "bank" ? "active" : ""}`} onClick={() => setActiveTab("bank")}>BANK</button>
        <button className={`tab ${activeTab === "education" ? "active" : ""}`} onClick={() => setActiveTab("education")}>EDUCATION</button>
      </div>

      <form className="employee-form" onSubmit={isEditMode ? handleUpdate : handleAdd}>

        {/* ---------------- PERSONAL ---------------- */}
        {activeTab === "personal" && (
          <>
            <h3>Personal Details</h3>
            <div className="employee-grid">

              <div className="form-field">
                <label>First Name</label>
                <input name="firstName" value={employee.firstName} onChange={handleChange}/>
              </div>

              <div className="form-field">
                <label>Last Name</label>
                <input name="lastName" value={employee.lastName} onChange={handleChange}/>
              </div>

              <div className="form-field">
                <label>Employee ID</label>
                <input name="empId" value={employee.empId} onChange={handleChange}/>
              </div>

              <div className="form-field">
                <label>Gender</label>
                <select name="gender" value={employee.gender} onChange={handleChange}>
                  <option value="">Gender</option>
                  <option>Male</option>
                  <option>Female</option>
                </select>
              </div>

              <div className="form-field">
                <label>Date of Birth</label>
                <input type="date" name="dob" value={employee.dob} onChange={handleChange}/>
              </div>

              <div className="form-field">
                <label>Marital Status</label>
                <select name="maritalStatus" value={employee.maritalStatus} onChange={handleChange}>
                  <option value="">Marital Status</option>
                  <option>Single</option>
                  <option>Married</option>
                </select>
              </div>

              <div className="form-field">
                <label>Email</label>
                <input type="email" name="email" value={employee.email} onChange={handleChange}/>
              </div>

              <div className="form-field">
                <label>Password</label>
                <input type="password" name="password" value={employee.password} onChange={handleChange}/>
              </div>

            </div>
          </>
        )}

        {/* ---------------- EMPLOYMENT ---------------- */}
        {activeTab === "employment" && (
          <>
            <h3>Employment Details</h3>
            <div className="employee-grid">

              {/* ===================== UPDATED FIELD ===================== */}
              <div className="form-field">
                <label>Designation</label>
                <select
                  name="designation"
                  value={employee.designation}
                  onChange={handleChange}
                >
                  <option value="">Select Designation</option>
                  {designations.map(d => (
                    <option key={d.id} value={d.title}>
                      {d.title}
                    </option>
                  ))}
                </select>
              </div>

              <div className="form-field">
                <label>Department</label>
                <select name="department" value={employee.department} onChange={handleChange}>
                  <option value="">Select Department</option>
                  <option>Frontend</option>
                  <option>Backend</option>
                  <option>QC (Quality Check)</option>
                  <option>Database</option>
                  <option>IT</option>
                  <option>Digital Marketing</option>
                  <option>HR</option>
                  <option>Sales</option>
                  <option>USIT Recruiters</option>
                  <option>Business Developers</option>
                  <option>Web Developer</option>
                </select>
              </div>

              <div className="form-field">
                <label>Salary</label>
                <input name="salary" value={employee.salary} onChange={handleChange}/>
              </div>

              <div className="form-field">
                <label>Role</label>
                <select name="role" value={employee.role} onChange={handleChange}>
                  <option value="">Role</option>
                  <option>Employee</option>
                  <option>Admin</option>
                </select>
              </div>

              <div className="form-field">
                <label>Select Skill</label>
                <select name="tempSkill" value={employee.tempSkill} onChange={handleChange}>
                  <option value="">Select Skill</option>
                  {skillOptions.map(s => (
                    <option key={s} value={s}>{s}</option>
                  ))}
                  <option value="Other">Other</option>
                </select>
              </div>

              {employee.tempSkill === "Other" && (
                <div className="form-field">
                  <label>Custom Skill</label>
                  <input name="customSkill" value={employee.customSkill} onChange={handleChange}/>
                </div>
              )}

              <button type="button" className="save-btn" onClick={addSkill}>
                Add Skill
              </button>

              <div style={{ gridColumn: "1 / span 2" }}>
                {employee.skills.map(skill => (
                  <span
                    key={skill}
                    style={{
                      padding: "6px 10px",
                      margin: "6px",
                      background: "#e3f2fd",
                      borderRadius: "20px",
                      display: "inline-block",
                      border: "1px solid #2196f3",
                      cursor: "pointer"
                    }}
                    onClick={() => removeSkill(skill)}
                  >
                    {skill} ✖
                  </span>
                ))}
              </div>

            </div>
          </>
        )}

        {/* ---------------- BANK ---------------- */}
        {activeTab === "bank" && (
          <>
            <h3>Bank Details</h3>
            <div className="employee-grid">

              <div className="form-field">
                <label>Bank Name</label>
                <input name="bankName" value={employee.bankName} onChange={handleChange}/>
              </div>

              <div className="form-field">
                <label>Account Number</label>
                <input name="accountNumber" value={employee.accountNumber} onChange={handleChange}/>
              </div>

              <div className="form-field">
                <label>IFSC Code</label>
                <input name="ifsc" value={employee.ifsc} onChange={handleChange}/>
              </div>

            </div>
          </>
        )}

        {/* ---------------- EDUCATION ---------------- */}
        {activeTab === "education" && (
          <>
            <h3>Educational Details</h3>
            <div className="employee-grid">

              <div className="form-field">
                <label>Highest Qualification</label>
                <select name="qualification" value={employee.qualification} onChange={handleChange}>
                  <option value="">Highest Qualification</option>
                  <option>B.Tech</option>
                  <option>M.Tech</option>
                  <option>BSc</option>
                  <option>MBA</option>
                  <option>MCA</option>
                  <option>Diploma</option>
                </select>
              </div>

              <div className="form-field">
                <label>University / College</label>
                <input name="university" value={employee.university} onChange={handleChange}/>
              </div>

              <div className="form-field">
                <label>Year of Passing</label>
                <input name="passingYear" value={employee.passingYear} onChange={handleChange}/>
              </div>

            </div>
          </>
        )}

        <button className="save-btn" type="submit">
          {isEditMode ? "Update Employee" : "Save Employee"}
        </button>

      </form>
    </div>
  );
}

export default AddEmployee;
